const body = $input.first().json.body || $input.first().json;
const { monsters, party, terrain, stats, hardcore } = body;

const td = {
  'open-field': 'Open Grassland — no cover, full movement, AOE hits all clustered targets',
  'dungeon': 'Stone Dungeon — 10-ft corridors, AOE limited to adjacent squares, retreat difficult',
  'forest': 'Dense Forest — half-cover available, difficult terrain, chokepoints'
};

let combatText = 'TERRAIN: ' + (td[terrain] || terrain) + '

=== MONSTERS ===
';
for (const m of (monsters || [])) {
  combatText += '
--- ' + m.name + ' (CR ' + m.cr + ') ---
HP: ' + m.hp + ' | AC: ' + m.ac + '
';
  combatText += 'STR:' + (m.str||10) + ' DEX:' + (m.dex||10) + ' CON:' + (m.con||10) + ' INT:' + (m.int||10) + ' WIS:' + (m.wis||10) + ' CHA:' + (m.cha||10) + '
';
  if (m.save && Object.keys(m.save).length) combatText += 'Saves: ' + Object.entries(m.save).map(([k,v]) => k.toUpperCase() + ' +' + (v||0)).join(', ') + '
';
  if (m.immune?.length) combatText += 'Damage Immunities: ' + [...m.immune].join(', ') + '
';
  if (m.resist?.length) combatText += 'Resistances: ' + [...m.resist].join(', ') + '
';
  if (m.conditionImmune?.length) combatText += 'Condition Immunities: ' + [...m.conditionImmune].join(', ') + '
';
  if (m.trait?.length) { combatText += 'TRAITS:
'; m.trait.forEach(t => combatText += '  ' + t + '
'); }
  if (m.allActions?.length) { combatText += 'ACTIONS:
'; m.allActions.forEach(a => combatText += '  ' + a + '
'); }
  if (m.reactions?.length) { combatText += 'REACTIONS:
'; m.reactions.forEach(r => combatText += '  ' + r + '
'); }
  if (m.legendaryActions?.length) { combatText += 'LEGENDARY ACTIONS (3 uses/round, spend at end of any other creature's turn):
'; m.legendaryActions.forEach(la => combatText += '  ' + la + '
'); }
  if (m.breathWeapon) combatText += 'BREATH WEAPON: ' + m.breathWeapon.name + ' — ' + m.breathWeapon.damage + ' ' + m.breathWeapon.dmgType + ' damage, DC ' + m.breathWeapon.dc + ' DEX save, Recharge 5-6
';
}
combatText += '
=== PARTY ===
';
for (const pc of (party || [])) {
  combatText += '
--- ' + pc.name + ' (' + pc.class + ' Lv' + (pc.level||5) + ') ---
HP: ' + pc.hp_max + ' | AC: ' + pc.ac + '
';
  combatText += 'Attack: +' + (pc.atk||0) + ' to hit | ' + (pc.dmgDice||'1d8') + '+' + (pc.dmgMod||0) + ' | ' + (pc.multi||1) + ' attacks/turn
';
  if (pc.spellDc) combatText += 'Spell Save DC: ' + pc.spellDc + '
';
  if (pc.subclass) combatText += 'Subclass: ' + pc.subclass + '
';
  if (pc.features?.length) { combatText += 'CLASS FEATURES:
'; pc.features.forEach(f => combatText += '  ' + f.name + ': ' + f.uses + ' uses' + (f.damage ? ', ' + f.damage : '') + '
'); }
}

// Build statistical context from 50-run analysis
let context = '';
if (stats) {
  const winPct = Math.round((stats.winRate || 0) * 100);
  context = `

STATISTICAL CONTEXT (from 50-run analysis of this exact encounter):
`;
  context += `- Party win rate: ${winPct}% | Average fight length: ${(stats.avgRounds||5).toFixed(1)} rounds | TPK rate: ${Math.round((stats.tpkRate||0)*100)}%
`;
  for (const [name, pc] of Object.entries(stats.pcs || {})) {
    context += `- ${name}: survived ${Math.round((pc.surv||0)*100)}% of fights, went unconscious ${(pc.downed||0).toFixed(1)}x per fight`;
    const topFu = Object.entries(pc.fuUsed||{}).filter(([,v])=>v>0.05).sort((a,b)=>b[1]-a[1]).slice(0,3);
    if (topFu.length) context += `, used: ${topFu.map(([k,v])=>k+' '+v.toFixed(1)+'x').join(', ')}`;
    context += '
';
  }
}

const systemPrompt = `You are a master Dungeon Master writing a vivid, mechanically accurate D&D 5e combat narrative.

The narrative should REFLECT the statistical reality — if the party usually wins, they probably win here too.

MECHANICAL RULES TO FOLLOW:
- Use ALL monster abilities by name: cast their actual spells, use reactions (Shield, Counterspell, Parry, Opportunity Attacks) when triggered, use ACTUAL legendary action options listed (not generic attacks), breath weapons recharge on 5-6
- Show dice rolls: e.g. [d20=17+7=24 vs AC 18, HIT] or [Dex save: d20=8+3=11 vs DC 16, FAIL]
- Track HP carefully, mention current HP at key moments
- Apply conditions: stunned creatures skip turns, frightened can't approach, prone gives disadvantage/advantage
- Death saves: 3 successes = stable, 3 failures = dead, nat 20 = revive at 1 HP

WRITING STYLE:
- Vivid and dramatic — make each action feel consequential
- Show the monsters' intelligence and tactics
- Highlight character moments: the fighter's desperate surge, the wizard's last spell slot
- 600-900 words total`;

const userMessage = combatText + context + '

Write the battle narrative.';

return [{ json: { systemPrompt, userMessage } }];

const item = $input.first().json;
const text = item.content?.[0]?.text || '';
return [{ json: { narrative: text } }];
